// ============================================================
// src/components/admin/PatientsTab.js
// ============================================================
import React, { useState, useEffect, useCallback } from "react";
import api from "../../utils/api";
import PrescriptionModal from "./PrescriptionModal";

const SERVICES_LIST = [
  "General Checkup & Cleaning","Cosmetic Dentistry / Smile Makeover","Dental Implants",
  "Orthodontics / Invisalign","Root Canal Therapy","Pediatric Dentistry","Oral Surgery",
  "Periodontal Treatment","Teeth Whitening","Emergency Dental Care","Follow-Up Visit","Other",
];

export default function PatientsTab({ showNotify, doctor }) {
  const [patients, setPatients] = useState([]);
  const [filtered, setFiltered] = useState([]);
  const [loading, setLoading] = useState(true);
  const [showNewForm, setShowNewForm] = useState(false);
  const [newPat, setNewPat] = useState({ name:"",mobile:"",email:"",age:"",gender:"",blood:"" });
  const [selectedPatient, setSelectedPatient] = useState(null);
  const [rxModal, setRxModal] = useState(null); // { visit, patient }

  // Visit form state
  const today = new Date().toISOString().split("T")[0];
  const nowTime = new Date().toTimeString().slice(0,5);
  const [visitForm, setVisitForm] = useState({ date: today, time: nowTime, service:"", amount:"", doctor: doctor?.name||"", toothNumbers:"", notes:"", medicines:"", nextVisitDate:"" });
  const [medRows, setMedRows] = useState([{ name:"", dose:"", freq:"", duration:"" }]);

  const loadPatients = useCallback(async () => {
    setLoading(true);
    try {
      const data = await api.get("/patients");
      setPatients(data);
      setFiltered(data);
    } catch (err) {
      showNotify("Error", err.message, true);
    }
    setLoading(false);
  }, []);

  useEffect(() => { loadPatients(); }, [loadPatients]);

  const filterPatients = (q) => {
    const term = q.toLowerCase();
    setFiltered(patients.filter(p =>
      (p.name||"").toLowerCase().includes(term) ||
      (p.mobile||"").includes(term) ||
      (p.email||"").toLowerCase().includes(term)
    ));
  };

  const createPatient = async () => {
    if (!newPat.name.trim()) { alert("Patient name is required."); return; }
    if (!newPat.mobile.trim()) { alert("Mobile number is required."); return; }
    try {
      await api.post("/patients", newPat);
      setNewPat({ name:"",mobile:"",email:"",age:"",gender:"",blood:"" });
      setShowNewForm(false);
      showNotify("Patient Profile Created! ✓", "New profile for " + newPat.name + " saved.");
      loadPatients();
    } catch (err) {
      showNotify("Error", err.message, true);
    }
  };

  const openPatient = async (p) => {
    try {
      const full = await api.get("/patients/" + p._id);
      setSelectedPatient(full);
      setVisitForm({ date: today, time: nowTime, service:"", amount:"", doctor: doctor?.name||"", toothNumbers:"", notes:"", medicines:"", nextVisitDate:"" });
      setMedRows([{ name:"", dose:"", freq:"", duration:"" }]);
    } catch (err) {
      showNotify("Error", err.message, true);
    }
  };

  const deletePatient = async () => {
    if (!window.confirm("Delete this patient profile and all their records? This cannot be undone.")) return;
    try {
      await api.delete("/patients/" + selectedPatient._id);
      showNotify("Profile Deleted", "Patient profile removed.");
      setSelectedPatient(null);
      loadPatients();
    } catch (err) {
      showNotify("Error", err.message, true);
    }
  };

  const addMedRow = () => setMedRows(r => [...r, { name:"", dose:"", freq:"", duration:"" }]);
  const updateMed = (i, k, v) => setMedRows(prev => prev.map((r, idx) => idx===i ? {...r,[k]:v} : r));
  const deleteMed = (i) => setMedRows(prev => prev.filter((_,idx) => idx!==i));

  const saveVisit = async () => {
    if (!visitForm.date || !visitForm.service) {
      showNotify("Missing Fields", "Please select a Visit Date and Service before saving.", true);
      return;
    }
    try {
      const payload = { ...visitForm, prescription: { medicineRows: medRows.filter(r => r.name.trim()) } };
      const updated = await api.post("/patients/" + selectedPatient._id + "/visits", payload);
      setSelectedPatient(updated);
      setVisitForm({ date: today, time: nowTime, service:"", amount:"", doctor: doctor?.name||"", toothNumbers:"", notes:"", medicines:"", nextVisitDate:"" });
      setMedRows([{ name:"", dose:"", freq:"", duration:"" }]);
      showNotify("Visit Recorded! ✓", "New visit record saved successfully.");
      loadPatients();
    } catch (err) {
      showNotify("Error", err.message, true);
    }
  };

  const deleteVisit = async (visitId) => {
    if (!window.confirm("Delete this visit record?")) return;
    try {
      const updated = await api.delete("/patients/" + selectedPatient._id + "/visits/" + visitId);
      setSelectedPatient(updated.patient);
      showNotify("Visit Deleted", "Visit record removed.");
      loadPatients();
    } catch (err) {
      showNotify("Error", err.message, true);
    }
  };

  const fmtDate = (dateStr) => {
    if (!dateStr) return "";
    const d = new Date(dateStr + "T00:00:00");
    return d.toLocaleDateString("en-IN", { day:"numeric", month:"long", year:"numeric" });
  };

  const totalRevenue = (visits = []) => {
    return visits.reduce((sum, v) => {
      const n = parseFloat((v.amount||"0").replace(/[^0-9.]/g,""));
      return sum + (isNaN(n) ? 0 : n);
    }, 0);
  };

  // ── LIST VIEW ────────────────────────────────────────────────
  if (!selectedPatient) {
    return (
      <div>
        <div className="admin-section-title">Patient Profiles</div>
        <div className="admin-section-desc">Create and manage individual patient profiles. Click a profile to view visit history and add new records.</div>

        <div className="patients-list-view">
          <input
            type="text"
            className="patient-search-bar"
            placeholder="🔍 Search patients by name or phone..."
            onChange={e => filterPatients(e.target.value)}
          />

          {showNewForm && (
            <div className="new-patient-form">
              <h4>➕ Create New Patient Profile</h4>
              <div className="new-patient-grid">
                {[["name","text","Full Name *","Patient full name"],["mobile","tel","Mobile Number *","+91 98765 43210"],["email","email","Email Address","patient@email.com"],["age","number","Age","Age"]].map(([k,t,label,ph]) => (
                  <div key={k}>
                    <div className="admin-row-label">{label}</div>
                    <input type={t} placeholder={ph} value={newPat[k]} onChange={e => setNewPat(p => ({...p,[k]:e.target.value}))} />
                  </div>
                ))}
                <div>
                  <div className="admin-row-label">Gender</div>
                  <select value={newPat.gender} onChange={e => setNewPat(p => ({...p,gender:e.target.value}))}>
                    <option value="">Select Gender</option>
                    <option>Male</option><option>Female</option><option>Other</option>
                  </select>
                </div>
                <div>
                  <div className="admin-row-label">Blood Group</div>
                  <input type="text" placeholder="e.g. B+" value={newPat.blood} onChange={e => setNewPat(p => ({...p,blood:e.target.value}))} />
                </div>
              </div>
              <div style={{ display:"flex", gap:10, flexWrap:"wrap" }}>
                <button className="add-visit-save-btn" onClick={createPatient}>💾 Save Patient Profile</button>
                <button className="btn-back-patients" onClick={() => setShowNewForm(false)}>Cancel</button>
              </div>
            </div>
          )}

          <div style={{ display:"flex", alignItems:"center", justifyContent:"space-between", marginBottom:14, flexWrap:"wrap", gap:10 }}>
            <div style={{ fontSize:13, color:"var(--gray-400)" }}>
              {loading ? "Loading patients..." : `${filtered.length} patient profile${filtered.length!==1?"s":""}`}
            </div>
            <button className="admin-add-btn" onClick={() => setShowNewForm(s => !s)}>
              {showNewForm ? "Cancel" : "+ New Patient Profile"}
            </button>
          </div>

          <div className="patient-profiles-grid">
            {loading ? (
              <div style={{ color:"var(--gray-400)", fontSize:14, padding:"20px 0", gridColumn:"1/-1" }}>Loading...</div>
            ) : filtered.length === 0 ? (
              <div style={{ color:"var(--gray-400)", fontSize:14, padding:"24px 0", gridColumn:"1/-1", textAlign:"center" }}>
                No patients yet. Click "+ New Patient Profile" to add your first patient.
              </div>
            ) : filtered.map(p => (
              <div key={p._id} className="patient-profile-card" onClick={() => openPatient(p)}>
                <div className="patient-avatar-icon">🧑‍⚕️</div>
                <div className="patient-card-name">{p.name}</div>
                <div className="patient-card-id">📞 {p.mobile || "—"}</div>
                <div className="patient-card-visits">📋 {p.visitCount||0} visit{p.visitCount!==1?"s":""}</div>
              </div>
            ))}
          </div>
        </div>
      </div>
    );
  }

  // ── DETAIL VIEW ──────────────────────────────────────────────
  const p = selectedPatient;
  const visits = p.visits || [];
  const total = totalRevenue(visits);

  return (
    <div>
      <div className="patient-detail-view open">
        <div className="patient-detail-header">
          <button className="btn-back-patients" onClick={() => setSelectedPatient(null)}>← Back to Patients</button>
          <div className="patient-avatar-icon" style={{ width:56, height:56, fontSize:26 }}>🧑‍⚕️</div>
          <div style={{ flex:1 }}>
            <h3>{p.name}</h3>
            <p style={{ fontSize:13, color:"var(--gray-400)" }}>{p.email}{p.email&&p.mobile?" · ":""}{p.mobile}</p>
            <div className="patient-info-row">
              {[p.age?"Age: "+p.age:null, p.gender||null, p.blood?"Blood: "+p.blood:null].filter(Boolean).map((t,i) => (
                <span key={i} className="patient-info-pill">{t}</span>
              ))}
            </div>
          </div>
          <div style={{ textAlign:"right", flexShrink:0 }}>
            <div style={{ fontSize:11, color:"var(--gray-400)", letterSpacing:"0.5px", textTransform:"uppercase", marginBottom:4 }}>Total Revenue</div>
            <div style={{ fontFamily:"Cormorant Garamond,serif", fontSize:26, fontWeight:600, color:"var(--teal)", lineHeight:1 }}>
              Rs. {total.toLocaleString("en-IN")}
            </div>
            <div style={{ fontSize:11, color:"var(--gray-400)", marginTop:2 }}>{visits.length} visit{visits.length!==1?"s":""}</div>
          </div>
          <button className="admin-del-btn" onClick={deletePatient} style={{ alignSelf:"flex-start", marginTop:4 }}>
            🗑️ Delete Profile
          </button>
        </div>

        {/* Add Visit Form */}
        <div className="add-visit-form">
          <h4>📋 Add New Visit Record</h4>
          <div className="add-visit-grid">
            <div>
              <div className="admin-row-label">Visit Date *</div>
              <input type="date" value={visitForm.date} onChange={e => setVisitForm(f => ({...f,date:e.target.value}))} />
            </div>
            <div>
              <div className="admin-row-label">Visit Time</div>
              <input type="time" value={visitForm.time} onChange={e => setVisitForm(f => ({...f,time:e.target.value}))} />
            </div>
            <div>
              <div className="admin-row-label">Service Taken *</div>
              <select value={visitForm.service} onChange={e => setVisitForm(f => ({...f,service:e.target.value}))}>
                <option value="">Select Service</option>
                {SERVICES_LIST.map(s => <option key={s} value={s}>{s}</option>)}
              </select>
            </div>
            <div>
              <div className="admin-row-label">Amount Charged (Rs.)</div>
              <input type="text" placeholder="e.g. 2500" value={visitForm.amount} onChange={e => setVisitForm(f => ({...f,amount:e.target.value}))} />
            </div>
            <div>
              <div className="admin-row-label">Treating Doctor</div>
              <input type="text" value={visitForm.doctor} onChange={e => setVisitForm(f => ({...f,doctor:e.target.value}))} />
            </div>
            <div>
              <div className="admin-row-label">Tooth Numbers</div>
              <input type="text" placeholder="e.g. 11, 21, 36" value={visitForm.toothNumbers} onChange={e => setVisitForm(f => ({...f,toothNumbers:e.target.value}))} />
            </div>
            <div>
              <div className="admin-row-label">Next Visit Date</div>
              <input type="date" value={visitForm.nextVisitDate} onChange={e => setVisitForm(f => ({...f,nextVisitDate:e.target.value}))} />
            </div>
          </div>
          <div>
            <div className="admin-row-label">Doctor's Notes / Diagnosis</div>
            <textarea value={visitForm.notes} onChange={e => setVisitForm(f => ({...f,notes:e.target.value}))} style={{ width:"100%", marginBottom:12 }} placeholder="Clinical notes, diagnosis, treatment details..." />
          </div>

          {/* Medicine Rows */}
          <div style={{ marginBottom:12 }}>
            <div className="admin-row-label" style={{ marginBottom:8 }}>💊 Prescription Medicines</div>
            <div style={{ display:"grid", gridTemplateColumns:"2fr 1fr 1fr 1fr auto", gap:6, marginBottom:6, fontSize:11, color:"var(--gray-400)" }}>
              <span>Medicine Name</span><span>Dose</span><span>Frequency</span><span>Duration</span><span></span>
            </div>
            {medRows.map((row, i) => (
              <div key={i} style={{ display:"grid", gridTemplateColumns:"2fr 1fr 1fr 1fr auto", gap:6, marginBottom:6 }}>
                <input type="text" placeholder="e.g. Ibuprofen 400mg" value={row.name} onChange={e => updateMed(i,"name",e.target.value)} style={{ padding:"8px 10px", border:"1.5px solid var(--gray-200)", borderRadius:7, fontFamily:"DM Sans,sans-serif", fontSize:12, outline:"none" }} />
                <input type="text" placeholder="e.g. 1 tab" value={row.dose} onChange={e => updateMed(i,"dose",e.target.value)} style={{ padding:"8px 10px", border:"1.5px solid var(--gray-200)", borderRadius:7, fontFamily:"DM Sans,sans-serif", fontSize:12, outline:"none" }} />
                <select value={row.freq} onChange={e => updateMed(i,"freq",e.target.value)} style={{ padding:"8px 10px", border:"1.5px solid var(--gray-200)", borderRadius:7, fontFamily:"DM Sans,sans-serif", fontSize:12, outline:"none" }}>
                  <option value="">Frequency</option>
                  {["Once daily","Twice daily","Three times daily","Four times daily","As needed","Before food","After food","At bedtime"].map(f => <option key={f} value={f}>{f}</option>)}
                </select>
                <input type="text" placeholder="e.g. 5 days" value={row.duration} onChange={e => updateMed(i,"duration",e.target.value)} style={{ padding:"8px 10px", border:"1.5px solid var(--gray-200)", borderRadius:7, fontFamily:"DM Sans,sans-serif", fontSize:12, outline:"none" }} />
                <button className="admin-del-btn" style={{ padding:"6px 10px", fontSize:12 }} onClick={() => deleteMed(i)}>✕</button>
              </div>
            ))}
            <button className="btn-back-patients" onClick={addMedRow} style={{ marginTop:4, fontSize:12 }}>+ Add Medicine</button>
          </div>

          <button className="add-visit-save-btn" onClick={saveVisit}>💾 Save Visit Record</button>
        </div>

        {/* Visit History */}
        <div className="visit-records-section">
          <h4>📅 Visit History ({visits.length})</h4>
          {visits.length === 0 ? (
            <div style={{ color:"var(--gray-400)", fontSize:13, padding:"10px 0" }}>No visits recorded yet.</div>
          ) : visits.map((v, i) => (
            <div key={v._id || i} className="visit-record-card">
              <div className="vrc-top">
                <div className="vrc-date">{fmtDate(v.visitDate)}{v.visitTime ? " at " + v.visitTime : ""}</div>
                {v.amount && <div className="vrc-amount">Rs. {v.amount}</div>}
              </div>
              <div className="vrc-service">{v.service}</div>
              {v.doctor && <div className="vrc-notes">👨‍⚕️ {v.doctor}</div>}
              {v.toothNumbers && <div className="vrc-notes">🦷 Tooth: {v.toothNumbers}</div>}
              {v.notes && <div className="vrc-notes" style={{ marginTop:4 }}>{v.notes}</div>}
              {v.nextVisitDate && (
                <div className="next-visit-pill">📅 Next Visit: {fmtDate(v.nextVisitDate)}</div>
              )}
              {(v.prescription?.medicineRows?.length > 0) && (
                <div style={{ marginTop:8, fontSize:12, color:"var(--teal)" }}>
                  💊 {v.prescription.medicineRows.length} medicine{v.prescription.medicineRows.length>1?"s":""} prescribed
                </div>
              )}
              <div className="vrc-actions">
                {(v.prescription || v.notes || v.service) && (
                  <button className="vrc-btn rx" onClick={() => setRxModal({ visit: v, patient: p })}>
                    📄 Generate Prescription PDF
                  </button>
                )}
                <button className="vrc-btn del" onClick={() => deleteVisit(v._id)}>🗑️ Delete</button>
              </div>
            </div>
          ))}
        </div>
      </div>

      {rxModal && (
        <PrescriptionModal
          visit={rxModal.visit}
          patient={rxModal.patient}
          doctor={{ name: rxModal.visit.doctor || doctor?.name || "Doctor" }}
          onClose={() => setRxModal(null)}
        />
      )}
    </div>
  );
}
